class Solution(object):
    def longestAlternatingSubarray(self, nums, threshold):
        n = len(nums)
        res = 0
        for i in range(n):
            if nums[i] % 2 == 0 and nums[i] <= threshold:
                length = 1
                for j in range(i + 1, n):
                    if nums[j] <= threshold and nums[j] % 2 != nums[j - 1] % 2:
                        length += 1
                    else:
                        break
                res = max(res, length)
        return res
